"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[37340],{27802:(e,i,l)=>{l.r(i),l.d(i,{data:()=>n});const n={key:"v-5849329c",path:"/mongodb/%E6%95%99%E7%A8%8B/net/%E6%9F%A5%E8%AF%A2%E5%AF%B9%E6%AF%94.html",title:"PCB C# MongoDB 查询(SQL,NOSQL,C#对比)",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"一.准备阶段",slug:"一-准备阶段",children:[]},{level:2,title:"二.查询全表",slug:"二-查询全表",children:[]},{level:2,title:"三.查询数据总数",slug:"三-查询数据总数",children:[]},{level:2,title:"四.查询并排序",slug:"四-查询并排序",children:[]},{level:2,title:"五.查询TOP前10条记录",slug:"五-查询top前10条记录",children:[]},{level:2,title:"六.查询从第6条到第10条记录（即：跳过前5条记录起的后5条记录）",slug:"六-查询从第6条到第10条记录-即-跳过前5条记录起的后5条记录",children:[]},{level:2,title:"七.查询distinct去除重复字段",slug:"七-查询distinct去除重复字段",children:[]},{level:2,title:"八.查询Group by分组",slug:"八-查询group-by分组",children:[]},{level:2,title:"九.查询条件>，>=，<，<=,<>",slug:"九-查询条件",children:[]},{level:2,title:"十.查询条件in与not in",slug:"十-查询条件in与not-in",children:[]},{level:2,title:"十一.查询模糊查询 like",slug:"十一-查询模糊查询-like",children:[]},{level:2,title:"十二.查询多条件逻辑 or与and",slug:"十二-查询多条件逻辑-or与and",children:[]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"mongodb/教程/net/查询对比.md"}},62201:(e,i,l)=>{l.r(i),l.d(i,{default:()=>s});const n=(0,l(57293).uE)('<h1 id="pcb-c-mongodb-查询-sql-nosql-c-对比" tabindex="-1"><a class="header-anchor" href="#pcb-c-mongodb-查询-sql-nosql-c-对比" aria-hidden="true">#</a> PCB C# MongoDB 查询(SQL,NOSQL,C#对比)</h1><p>转自:https://www.cnblogs.com/pcbren/p/9539543.html</p><h2 id="一-准备阶段" tabindex="-1"><a class="header-anchor" href="#一-准备阶段" aria-hidden="true">#</a> 一.准备阶段</h2><p>​ 1.查询数据清单准备</p><p>​ <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202203201502605.png" alt="img"></p><p>​ 2.这里先将SQL语句执行顺序列出来，方便后面语句对比更好理解</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>SELECT\nDISTINCT  \n&lt;Top Num&gt; &lt;select list&gt;\nFROM [left_table]\n&lt;join_type&gt; JOIN &lt;right_table&gt;\n             ON &lt;join_condition&gt;\nWHERE &lt;where_condition&gt;\nGROUP BY &lt;group_by_list&gt;\nWITH &lt;CUBE | RollUP&gt;\nHAVING &lt;having_condition&gt;\nORDER BY &lt;order_by_list&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="二-查询全表" tabindex="-1"><a class="header-anchor" href="#二-查询全表" aria-hidden="true">#</a> 二.查询全表</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select * from ppeflow\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code> db.ppeflow.find() \n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><pre><code>  3. MongoDB  C#\n</code></pre><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter;   //创建过滤\nFilterDefinition&lt;ppeflow&gt; filter = builderFilter.Empty;//过滤为空\nvar resultList = ppeflows.Find(filter).ToList();//获取集合 \n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="三-查询数据总数" tabindex="-1"><a class="header-anchor" href="#三-查询数据总数" aria-hidden="true">#</a> 三.查询数据总数</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select count(1) from ppeflow\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.find({}).count()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="3"><li>MongoDB C#</li></ol><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nFilterDefinition&lt;ppeflow&gt; filter = builderFilter.Empty;//过滤为空\nvar result = ppeflows.CountDocuments(filter); //获得集合数量\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="四-查询并排序" tabindex="-1"><a class="header-anchor" href="#四-查询并排序" aria-hidden="true">#</a> 四.查询并排序</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select * from ppeflow order by orderid\nselect *from ppeflow order by orderid desc \n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.find().sort({&#39;orderid&#39;:1})\ndb.ppeflow.find().sort({&#39;orderid&#39;:-1})\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><pre><code>  3. MongoDB  C#  \n</code></pre><p>方式一</p><div class="language-C# ext-C# line-numbers-mode"><pre class="language-C#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nFilterDefinition&lt;ppeflow&gt; filter = builderFilter.Empty;//过滤为空\nvar builderSort = Builders&lt;ppeflow&gt;.Sort.Ascending(t =&gt; t.orderid); //创建排序\nvar resultList = ppeflows.Find(filter).Sort(builderSort).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>方式二</p><div class="language-C# ext-C# line-numbers-mode"><pre class="language-C#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过\nFilterDefinition&lt;ppeflow&gt; filter = builderFilter.Empty;//过滤为空\nvar resultList = ppeflows.Find(filter).SortByDescending(t =&gt; t.orderid).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="五-查询top前10条记录" tabindex="-1"><a class="header-anchor" href="#五-查询top前10条记录" aria-hidden="true">#</a> 五.查询TOP前10条记录</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select top 10 * from ppeflow\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.find().limit(10)\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>MongoDB C#</li></ol><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nFilterDefinition&lt;ppeflow&gt; filter = builderFilter.Empty;//过滤为空\nvar resultList = ppeflows.Find(filter).Limit(10).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="六-查询从第6条到第10条记录-即-跳过前5条记录起的后5条记录" tabindex="-1"><a class="header-anchor" href="#六-查询从第6条到第10条记录-即-跳过前5条记录起的后5条记录" aria-hidden="true">#</a> 六.查询从第6条到第10条记录（即：跳过前5条记录起的后5条记录）</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select * from ppeflow limit 5,5          \n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.find().skip(5).limit(5)\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><pre><code>  3. MongoDB  C#  \n</code></pre><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nFilterDefinition&lt;ppeflow&gt; filter = builderFilter.Empty;//过滤为空\nvar resultList = ppeflows.Find(filter).Skip(5).Limit(5).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="七-查询distinct去除重复字段" tabindex="-1"><a class="header-anchor" href="#七-查询distinct去除重复字段" aria-hidden="true">#</a> 七.查询distinct去除重复字段</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select DISTINCT techname from ppeflow\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.distinct(&#39;techname&#39;)\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>MongoDB C#</li></ol><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nFilterDefinition&lt;ppeflow&gt; filter = builderFilter.Empty;//过滤为空\nvar resultList = ppeflows.Distinct(tt =&gt; tt.techname, filter).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="八-查询group-by分组" tabindex="-1"><a class="header-anchor" href="#八-查询group-by分组" aria-hidden="true">#</a> 八.查询Group by分组</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select techname,count(1) as total from ppeflow group by techname\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.group({key:{ &quot;techname&quot;:true},initial: {techname:&#39;&#39;,total: 0},reduce: function(doc, out)       {          out.techname = doc.techname;          out.total += doc.orderid;        }})\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>MongoDB C#</li></ol><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>            //待完善\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="九-查询条件" tabindex="-1"><a class="header-anchor" href="#九-查询条件" aria-hidden="true">#</a> 九.查询条件&gt;，&gt;=，&lt;，&lt;=,&lt;&gt;</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select techname from ppeflow where orderid &gt; 10\nselect techname from ppeflow where orderid &gt;= 10\nselect techname from ppeflow where orderid &lt; 10\nselect techname from ppeflow where orderid &lt;= 10\nselect techname from ppeflow where orderid &lt;&gt; 10\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.find({&#39;orderid&#39;:{$gt:10}},{&#39;techname&#39;:1})db.ppeflow.find({&#39;orderid&#39;:{$gte:10}},{&#39;techname&#39;:1})db.ppeflow.find({&#39;orderid&#39;:{$lt:10}},{&#39;techname&#39;:1})db.ppeflow.find({&#39;orderid&#39;:{$lte:10}},{&#39;techname&#39;:1})db.ppeflow.find({&#39;orderid&#39;:{$ne:10}},{&#39;techname&#39;:1})\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>MongoDB C#</li></ol><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\n            FilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\n            FilterDefinition&lt;ppeflow&gt; filter = builderFilter.Where(t =&gt; t.orderid &gt; 10); ;//过滤条件  改为对应的&gt;=,&lt;,&lt;=,!= \nvar resultList = ppeflows.Find(filter).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="十-查询条件in与not-in" tabindex="-1"><a class="header-anchor" href="#十-查询条件in与not-in" aria-hidden="true">#</a> 十.查询条件in与not in</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select * from ppeflow where orderid  in (10,11,12)\nselect * from ppeflow where orderid  not in (10,11,12)\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.find({&#39;orderid&#39;:{$in:[10,11,12]}})\ndb.ppeflow.find({&#39;orderid&#39;:{$nin:[10,11,12]}})\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>MongoDB C#</li></ol><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nvar filter = builderFilter.In(tt =&gt; tt.orderid, new List&lt;int&gt; { 10, 11, 12 });//In 条件 或Nin\nvar resultList = ppeflows.Find(filter).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="十一-查询模糊查询-like" tabindex="-1"><a class="header-anchor" href="#十一-查询模糊查询-like" aria-hidden="true">#</a> 十一.查询模糊查询 like</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select * from ppeflow where techname like &#39;%钻孔%&#39;\nselect * from ppeflow where techname like &#39;钻孔%&#39;\nselect * from ppeflow where techname like &#39;%钻孔&#39;\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>说明：i 忽略大小写  m 多行匹配模式  x 忽略非转义的空白字符   s 单 匹配模式db.ppeflow.find( { &#39;techname&#39;: /钻孔/i } )db.ppeflow.find( { &#39;techname&#39;: /钻孔$/i } )db.ppeflow.find( { &#39;techname&#39;: /^钻孔/i } )\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>MongoDB C#</li></ol><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nvar filter = builderFilter.Regex(tt =&gt; tt.techname, new BsonRegularExpression(&quot;/钻孔/i&quot;)); //正则匹配\nvar resultList = ppeflows.Find(filter).ToList();//获取集合\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="十二-查询多条件逻辑-or与and" tabindex="-1"><a class="header-anchor" href="#十二-查询多条件逻辑-or与and" aria-hidden="true">#</a> 十二.查询多条件逻辑 or与and</h2><p>​ 1. SQL:</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>select * from ppeflow where techname = &#39;开料&#39; or techname = &#39;钻孔&#39;\nselect * from ppeflow where orderid = 2 and techname = &#39;钻孔&#39;\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>​ 2. MongoDB NO SQL</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>db.ppeflow.find({$or:[{&#39;techname&#39;:&#39;开料&#39;},{&#39;techname&#39;:&#39;钻孔&#39;}]})\ndb.ppeflow.find({$and:[{&#39;orderid&#39;:2},{&#39;techname&#39;:&#39;钻孔&#39;}]})\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><pre><code>  3. MongoDB  C#  \n</code></pre><p>C# or</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nvar filter1 = builderFilter.Eq(tt =&gt; tt.techname, &quot;开料&quot;);\nvar filter2 = builderFilter.Eq(tt =&gt; tt.techname, &quot;钻孔&quot;);\nvar filter = builderFilter.Or(filter1, filter2);\nvar resultList = ppeflows.Find(filter).ToList();//获取集合\n//ppeflows.AsQueryable().Where(tt =&gt; tt.techname == &quot;开料&quot; || tt.techname == &quot;钻孔&quot;).ToList();   //lamda一种简写\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>C# and</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>IMongoCollection&lt;ppeflow&gt; ppeflows = db.GetCollection&lt;ppeflow&gt;(&quot;ppeflow&quot;);//指定数据库\nFilterDefinitionBuilder&lt;ppeflow&gt; builderFilter = Builders&lt;ppeflow&gt;.Filter; //创建过滤\nvar filter1 = builderFilter.Eq(tt =&gt; tt.orderid, 2);\nvar filter2 = builderFilter.Eq(tt =&gt; tt.techname, &quot;钻孔&quot;);\nvar filter = builderFilter.And(filter1, filter2);\nvar resultList = ppeflows.Find(filter).ToList();//获取集合\n//ppeflows.AsQueryable().Where(tt =&gt; tt.orderid == 2 &amp;&amp; tt.techname == &quot;钻孔&quot;).ToList();  //lamda一种简写\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',90),d={},s=(0,l(63243).Z)(d,[["render",function(e,i){return n}]])},63243:(e,i)=>{i.Z=(e,i)=>{const l=e.__vccOpts||e;for(const[e,n]of i)l[e]=n;return l}}}]);